    k_now = plot_k_list(i);

    if k_now <= cfg.k_emp_max

        idx_emp = find(k_emp == k_now, 1);
        e = err_cell{idx_emp};
        type_str = 'Empirical';
        color_hist = [0.78, 0.86, 0.95];
        color_line = [0.00, 0.20, 0.80];
        suffix_str = 'empirical';

    else

        idx_val = find(k_vals == k_now, 1);
        e = saved_noise_for_plot{idx_val};
        type_str = 'Extrapolated';
        color_hist = [0.90, 0.88, 0.95];
        color_line = [0.85, 0.10, 0.10];
        suffix_str = 'extrapolated';
    end

    e = e(isfinite(e));

    if isempty(e)
        warning('No valid residuals found for k = %d. Skipping.', k_now);
        continue;
    end

    % Recalculate display features from the current residual distribution.
    idx_main_show  = (e >= region.main(1))  & (e < region.main(2));
    idx_right_show = (e >= region.right(1)) & (e < region.right(2));

    val_PM = mean(idx_main_show);
    val_PR = mean(idx_right_show);

    eR_show = e(idx_right_show);

    if ~isempty(eR_show)

        curr_muR = mean(eR_show);

        val_sigR = iqr(eR_show) / 1.349;

        if numel(eR_show) < 4 || val_sigR == 0 || isnan(val_sigR)
            val_sigR = std(eR_show);
        end

        val_sigR = max(val_sigR, 1e-4);

    else

        curr_muR = mean(region.right);
        val_sigR = 0.005;
    end

    fig_dist = figure( ...
        'Color', 'w', ...
        'Units', 'centimeters', ...
        'Position', [2, 2, 5, 4], ...
        'PaperUnits', 'centimeters', ...
        'PaperPosition', [0, 0, 5, 4], ...
        'PaperSize', [5, 4], ...
        'InvertHardcopy', 'off', ...
        'Resize', 'off', ...
        'Name', sprintf('ExD03a_residual_distribution_k_%02d_%s', k_now, suffix_str));

    hold on;
    grid on;
    box on;

    histogram(e, cfg.hist_bins, ...
        'Normalization', 'pdf', ...
        'FaceColor', color_hist, ...
        'EdgeColor', 'none', ...
        'FaceAlpha', 0.68);

    [f, xi] = ksdensity(e, 'Bandwidth', cfg.kde_bw);

    % Highlight the main-mode and right-mode regions.
    idx_m = (xi >= region.main(1)) & (xi <= region.main(2));

    if any(idx_m)
        area(xi(idx_m), f(idx_m), ...
            'FaceColor', color_main_area, ...
            'FaceAlpha', 0.42, ...
            'EdgeColor', 'none');
    end

    idx_r = (xi >= region.right(1)) & (xi <= region.right(2));

    if any(idx_r)
        area(xi(idx_r), f(idx_r), ...
            'FaceColor', color_right_area, ...
            'FaceAlpha', 0.42, ...
            'EdgeColor', 'none');
    end

    plot(xi, f, '-', ...
        'Color', color_line, ...
        'LineWidth', 1.1);

    % Visualize zero bias and right-mode width.
    xlim([-0.06, 0.06]);

    yl = ylim;
    ylim([0, yl(2) * 1.18]);

    x_left = curr_muR - val_sigR;
    x_right = curr_muR + val_sigR;
    val_SigmaR_width = x_right - x_left;

    xline(0, 'k--', 'LineWidth', 0.9);
    xline(x_left, '--', 'Color', [0.65, 0.15, 0.15], 'LineWidth', 0.8);
    xline(x_right, '--', 'Color', [0.65, 0.15, 0.15], 'LineWidth', 0.8);

    xlabel('Residual', ...
        'FontName', 'Arial', ...
        'FontSize', 7);

    ylabel('Density', ...
        'FontName', 'Arial', ...
        'FontSize', 7);

    ax = gca;

    ax.FontName = 'Arial';
    ax.FontSize = 6;
    ax.LineWidth = 0.5;
    ax.Units = 'normalized';
    ax.Position = [0.18, 0.20, 0.75, 0.70];
    ax.GridLineStyle = ':';
    ax.GridAlpha = 0.20;

    out_png = fullfile(cfg.dist_dir, ...
        sprintf('ExD03a_residual_distribution_k_%02d_%s.png', k_now, suffix_str));

    out_fig = fullfile(cfg.dist_dir, ...
        sprintf('ExD03a_residual_distribution_k_%02d_%s.fig', k_now, suffix_str));

    local_save_figure(fig_dist, out_fig, out_png, cfg.png_resolution);

